library(foreach)
library(doParallel)




calc &lt;- function(n) {
  vals &lt;- rexp(n, 1)
  m &lt;- mean(vals)
  v &lt;- var(vals)
  c(m, v)
}

c1 &lt;- makeCluster(3)
registerDoParallel(c1)

m_v &lt;- foreach(i = 1:100, .combine = rbind) %dopar% {
  calc(n = 1000)
}

stopCluster(c1)
colnames(m_v) &lt;- c("Mean", "Variance")
head(m_v)

